129→function seedStoreLoaded(points: number) {
130→  const state = useRootStore.getState() as Record<string, any>;
131→  if (state.pointsExtractActions) {
132→    state.pointsExtractActions.setBalance(points);
133→    state.pointsExtractActions.setExtractData(MOCK_EXTRACT_DATA);
134→  }
